# 1. Database Setup (SQLAlchemy)

Base = declarative_base()

# Association table for Product-Category many-to-many relationship
product_category_association = Table(
    'product_category_association',
    Base.metadata,
    Column('product_id', Integer, ForeignKey('products.id'), primary_key=True),
    Column('category_id', Integer, ForeignKey('categories.id'), primary_key=True)
)

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    contact_email = Column(String, unique=True)
    products = relationship("Product", back_populates="seller", lazy="selectin")

    def __repr__(self):
        return f"<Seller(id={self.id}, name='{self.name}')>"

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, unique=True, index=True)
    products = relationship("Product", secondary=product_category_association, back_populates="categories", lazy="selectin")

    def __repr__(self):
        return f"<Category(id={self.id}, name='{self.name}')>"

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    description = Column(String)
    price = Column(Float)
    seller_id = Column(Integer, ForeignKey('sellers.id'))

    seller = relationship("Seller", back_populates="products", lazy="selectin")
    reviews = relationship("Review", back_populates="product", lazy="selectin")
    images = relationship("Image", back_populates="product", lazy="selectin")
    categories = relationship(
        "Category",
        secondary=product_category_association,
        back_populates="products",
        lazy="selectin"
    )

    def __repr__(self):
        return f"<Product(id={self.id}, name='{self.name}')>"

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True, index=True)
    url = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="images", lazy="selectin")

    def __repr__(self):
        return f"<Image(id={self.id}, url='{self.url[:30]}...')>"

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True, index=True)
    rating = Column(Integer)  # e.g., 1-5
    comment = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="reviews", lazy="selectin")

    def __repr__(self):
        return f"<Review(id={self.id}, rating={self.rating}, comment='{self.comment[:30]}...')>"


