# 2. GraphQL Schema (Strawberry)

# Helper function to get a new DB session
async def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

@strawberry.type
class SellerType:
    id: int
    name: str
    contact_email: str

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    url: str

@strawberry.type
class ReviewType:
    id: int
    rating: int
    comment: str

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: float
    seller: SellerType
    categories: list[CategoryType]
    images: list[ImageType]
    reviews: list[ReviewType]

@strawberry.type
class Query:
    @strawberry.field
    async def products(self, info: strawberry.Info, limit: int = 100, offset: int = 0) -> list[ProductType]:
        """
        Retrieves a list of products with all their related data.
        Relationships are eagerly loaded to prevent N+1 queries for direct relations.
        """
        # Get the SQLAlchemy session from the info context
        db_session_generator = info.context["get_db"]
        async for db in db_session_generator():
            # Eagerly load all direct relationships using selectinload
            # This ensures that when products are fetched, their associated sellers,
            # categories, images, and reviews are loaded efficiently in a minimal
            # number of additional queries (one per relationship type).
            stmt = select(Product).options(
                selectinload(Product.seller),
                selectinload(Product.categories),
                selectinload(Product.images),
                selectinload(Product.reviews)
            ).offset(offset).limit(limit)
            
            result = await db.execute(stmt)
            products = result.scalars().unique().all() # .unique() for many-to-many to avoid duplicate products
            return products

schema = strawberry.Schema(query=Query)

# 3. API Endpoint (FastAPI)
app = FastAPI()

# Initialize database on startup
@app.on_event("startup")
async def startup_event():
    init_db()

graphql_app = GraphQLRouter(
    schema,
    # Pass the session generator to the context, so resolvers can access it
    context_getter=lambda: {"get_db": get_db} 
)

app.include_router(graphql_app, prefix="/graphql")